import{_ as o,c as r,o as i,aj as t}from"./chunks/framework.HLg5PcC2.js";const h=JSON.parse('{"title":"Environment Variables","description":"","frontmatter":{},"headers":[],"relativePath":"reference/primitive-app/config/env-config.md","filePath":"reference/primitive-app/config/env-config.md"}'),a={name:"reference/primitive-app/config/env-config.md"};function n(l,e,s,d,c,u){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to “Environment Variables”">​</a></h1><p>Primitive apps use Vite environment variables (prefixed with <code>VITE_</code>) for configuration. These are defined in <code>.env</code> (development) and <code>.env.production</code> (production) files.</p><h2 id="required-variables" tabindex="-1">Required Variables <a class="header-anchor" href="#required-variables" aria-label="Permalink to “Required Variables”">​</a></h2><h3 id="vite-app-id" tabindex="-1"><code>VITE_APP_ID</code> <a class="header-anchor" href="#vite-app-id" aria-label="Permalink to “VITE_APP_ID”">​</a></h3><ul><li><strong>Type</strong>: <code>string</code></li><li><strong>Purpose</strong>: Your Primitive App ID from the admin console.</li><li><strong>Example</strong>: <code>VITE_APP_ID=01KFEV1VGXA12625JEQKNDAXVH</code></li></ul><h3 id="vite-api-url" tabindex="-1"><code>VITE_API_URL</code> <a class="header-anchor" href="#vite-api-url" aria-label="Permalink to “VITE_API_URL”">​</a></h3><ul><li><strong>Type</strong>: <code>string</code></li><li><strong>Purpose</strong>: The Primitive API server URL.</li><li><strong>Development</strong>: <code>https://js-bao-wss-test.adriangraham.workers.dev</code></li><li><strong>Production</strong>: <code>https://primitiveapi.com</code></li></ul><h3 id="vite-ws-url" tabindex="-1"><code>VITE_WS_URL</code> <a class="header-anchor" href="#vite-ws-url" aria-label="Permalink to “VITE_WS_URL”">​</a></h3><ul><li><strong>Type</strong>: <code>string</code></li><li><strong>Purpose</strong>: The Primitive WebSocket server URL for real-time sync.</li><li><strong>Development</strong>: <code>wss://js-bao-wss-test.adriangraham.workers.dev</code></li><li><strong>Production</strong>: <code>wss://primitiveapi.com</code></li></ul><h3 id="vite-oauth-redirect-uri" tabindex="-1"><code>VITE_OAUTH_REDIRECT_URI</code> <a class="header-anchor" href="#vite-oauth-redirect-uri" aria-label="Permalink to “VITE_OAUTH_REDIRECT_URI”">​</a></h3><ul><li><strong>Type</strong>: <code>string</code></li><li><strong>Purpose</strong>: The OAuth callback URL for your app. Must match what&#39;s configured in the Primitive Admin console and your OAuth provider.</li><li><strong>Development</strong>: <code>http://localhost:5173/oauth/callback</code></li><li><strong>Production</strong>: <code>https://your-domain.com/oauth/callback</code></li></ul><h3 id="vite-base-url" tabindex="-1"><code>VITE_BASE_URL</code> <a class="header-anchor" href="#vite-base-url" aria-label="Permalink to “VITE_BASE_URL”">​</a></h3><ul><li><strong>Type</strong>: <code>string</code></li><li><strong>Purpose</strong>: Base URL for your application. Used for generating links in document invitations and other places.</li><li><strong>Development</strong>: <code>http://localhost:5173</code></li><li><strong>Production</strong>: <code>https://your-domain.com</code></li></ul><h2 id="optional-variables" tabindex="-1">Optional Variables <a class="header-anchor" href="#optional-variables" aria-label="Permalink to “Optional Variables”">​</a></h2><h3 id="vite-enable-auth-proxy" tabindex="-1"><code>VITE_ENABLE_AUTH_PROXY</code> <a class="header-anchor" href="#vite-enable-auth-proxy" aria-label="Permalink to “VITE_ENABLE_AUTH_PROXY”">​</a></h3><ul><li><strong>Type</strong>: <code>&quot;true&quot; | &quot;false&quot;</code></li><li><strong>Default</strong>: <code>&quot;false&quot;</code></li><li><strong>Purpose</strong>: Enable the OAuth proxy for production deployments. Typically disabled for development and enabled in production.</li></ul><h3 id="vite-log-level" tabindex="-1"><code>VITE_LOG_LEVEL</code> <a class="header-anchor" href="#vite-log-level" aria-label="Permalink to “VITE_LOG_LEVEL”">​</a></h3><ul><li><strong>Type</strong>: <code>&quot;debug&quot; | &quot;info&quot; | &quot;warn&quot; | &quot;error&quot;</code></li><li><strong>Default</strong>: <code>&quot;info&quot;</code></li><li><strong>Purpose</strong>: Controls the logging verbosity. Your app reads this and passes it to <code>createPrimitiveApp({ logLevel })</code>.</li><li><strong>Recommendation</strong>: Use <code>&quot;info&quot;</code> or <code>&quot;debug&quot;</code> for development, <code>&quot;warn&quot;</code> for production.</li></ul>',18)])])}const g=o(a,[["render",n]]);export{h as __pageData,g as default};
